 /* ════════════════════════════════════════════════════ */
 /* SLIDE 3 — THE BOOTSTRAP                            */
 /* ════════════════════════════════════════════════════ */
 .slide-3 { background: var(--bg-dark); }
 .slide-3 .slide-label { color: var(--accent-amber); }

 .slide-3 .timeline {
   display: flex;
   flex-direction: column;
   gap: 0;
   margin-top: 16px;
 }
 .slide-3 .timeline-item {
   display: flex;
   gap: 24px;
   padding: 24px 0;
 }
 .slide-3 .timeline-marker {
   display: flex;
   flex-direction: column;
   align-items: center;
   flex-shrink: 0;
   width: 48px;
 }
 .slide-3 .timeline-dot {
   width: 20px;
   height: 20px;
   border-radius: 50%;
   flex-shrink: 0;
 }
 .slide-3 .timeline-line {
   width: 2px;
   flex: 1;
   min-height: 20px;
   background: var(--border);
 }
 .slide-3 .timeline-content h3 {
   font-size: 24px;
   font-weight: 700;
   color: var(--text-primary);
   margin-bottom: 6px;
 }
 .slide-3 .timeline-content p {
   font-size: 20px;
   color: var(--text-secondary);
   line-height: 1.5;
 }

